  ('social-worker-moex-01744', 'social-worker', 'social-worker-moex-108-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '依據兒童及少年福利與權益保障法，對於目睹家庭暴力之兒童及少年，經直轄市、縣（市）主管 機關列為保護個案者，該主管機關最遲應於下列多久時間內提出兒童及少年家庭處遇計畫？', '["1個月", "2個月", "3個月", "6個月"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "ff75e56582d6", "answer_pdf_sha1": "cf487df9a01b", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
