  ('social-worker-moex-01746', 'social-worker', 'social-worker-moex-108-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '依據身心障礙者權益保障法，身心障礙者支持服務之規定，下列敘述何者正確？', '["未提供對號座之大眾運輸工具應設置供身心障礙者及老弱婦孺優先乘坐之博愛座，其比率不低 於總座位數百分之五", "公共停車場應保留百分之一停車位，作為行動不便之身心障礙者專用停車位", "各級主管機關應輔導視覺功能障礙者設立以從事按摩為業務之勞動合作社", "各級主管機關應定期輔導、查核及評鑑身心障礙福利機構，其輔導、查核及改善情形應納入評 鑑指標項目，其評鑑結果共分為優等、甲等、乙等三個等第"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "ff75e56582d6", "answer_pdf_sha1": "cf487df9a01b", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01747', 'social-worker', 'social-worker-moex-108-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '下列何者不屬於家庭暴力防治法所定之家庭成員？', '["配偶或前配偶", "現有或曾有同居關係、家長家屬或家屬間關係者", "現為或曾為直系血親或直系姻親", "現為或曾為五親等以內之旁系血親或旁系姻親"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "ff75e56582d6", "answer_pdf_sha1": "cf487df9a01b", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01748', 'social-worker', 'social-worker-moex-108-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '依據家庭暴力防治法規定，下列何者並非屬於暫時保護令或緊急保護令的命令內容？', '["命相對人遷出被害人、目睹家庭暴力兒童及少年或其特定家庭成員之住居所；必要時，並得禁 止相對人就該不動產為使用、收益或處分行為", "定暫時對未成年子女權利義務之行使或負擔，由當事人之一方或雙方共同任之、行使或負擔之 內容及方法；必要時，並得命交付子女", "命相對人完成加害人處遇計畫", "禁止相對人查閱被害人及受其暫時監護之未成年子女戶籍、學籍、所得來源相關資訊"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "ff75e56582d6", "answer_pdf_sha1": "cf487df9a01b", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01749', 'social-worker', 'social-worker-moex-108-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '低收入戶成員中，下列何者不屬於社會救助法第12條明訂現金給付可以增加補助之對象？', '["年滿65歲", "未滿12歲之兒童", "領有身心障礙手冊或身心障礙證明", "懷胎滿3個月"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "ff75e56582d6", "answer_pdf_sha1": "cf487df9a01b", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01750', 'social-worker', 'social-worker-moex-108-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '依社會工作師法對公會之規定，下列敘述何者正確？', '["直轄市及縣（市）社會工作師達5人以上者或社會工作督導員資格超過5年以上資深者，即可 成立該區之社會工作師公會", "直轄市及縣（市）社會工作師達10人以上者，即可成立該區之社會工作師公會；且擔任社會 工作師年資至少需有10年以上", "直轄市及縣（市）社會工作師達15人以上者，得成立該區域之社會工作師公會；不足15人者， 得加入鄰近區域之公會", "資深社會工作員年資有10年以上和領有社會工作師證照者共達5人，即可自組成立社會工作 師公會或加入聯合會"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "ff75e56582d6", "answer_pdf_sha1": "cf487df9a01b", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
